// bun typecheck catches this before execution — no build step needed
import { serve } from "bun";

type Handler = (req: Request) => Response | Promise<Response>;

const json = <T>(data: T, status = 200): Response =>
  new Response(JSON.stringify(data), {
    status,
    headers: { "Content-Type": "application/json" },
  });

const handler: Handler = async (req) => {
  const body = await req.json<{ name: string }>();
  return json({ hello: body.name.toUpperCase() }); // type-safe: name is string
};

serve({ port: 3000, fetch: handler });

import { Bun } from 'bun';

type Result<T, E> = { ok: true; data: T } | { ok: false; error: E };

async function readConfig(path: string): Promise<Result<string, Error>> {
  try {
    const text = await Bun.file(path).text();
    return { ok: true, data: text };
  } catch (e) {
    return { ok: false, error: e as Error };
  }
}

Bun.serve({
  async fetch(req) {
    const result = await readConfig('./config.json');
    if (!result.ok) return new Response('Config missing', { status: 500 });
    return new Response(result.data);
  },
  error(err) {
    console.error('[unhandled]', err);
    return new Response('Internal error', { status: 500 });
  },
});

