import { serve } from "bun";

function getRuntimeMetrics() {
  const mem = process.memoryUsage();
  Bun.gc(false); // async hint to JSC GC
  return {
    heapUsedMB: (mem.heapUsed / 1024 / 1024).toFixed(2),
    heapTotalMB: (mem.heapTotal / 1024 / 1024).toFixed(2),
    externalMB: (mem.external / 1024 / 1024).toFixed(2),
    rss: (mem.rss / 1024 / 1024).toFixed(2),
  };
}

serve({
  port: 9091,
  fetch(req) {
    if (new URL(req.url).pathname === "/metrics") {
      const m = getRuntimeMetrics();
      const body = Object.entries(m)
        .map(([k, v]) => `bun_${k} ${v}`)
        .join("\n");
      return new Response(body, { headers: { "Content-Type": "text/plain" } });
    }
    return new Response("not found", { status: 404 });
  },
});

// server.ts — run one process per core, all bound to :3000
import { cpus } from "os";

if (!process.env.IS_WORKER) {
  for (let i = 0; i < cpus().length; i++) {
    Bun.spawn(["bun", "run", "server.ts"], {
      env: { ...process.env, IS_WORKER: "1" },
      stdout: "inherit",
    });
  }
} else {
  Bun.serve({
    port: 3000,
    reusePort: true,
    fetch(req) {
      return new Response(`pid ${process.pid}`);
    },
  });
}

