// Bun-native HTTP server with SQLite — no npm installs needed
import { Database } from "bun:sqlite";

const db = new Database("app.db");
db.run("CREATE TABLE IF NOT EXISTS hits (path TEXT, ts INTEGER)");

const insert = db.prepare("INSERT INTO hits VALUES ($path, $ts)");

Bun.serve({
  port: 3000,
  fetch(req) {
    insert.run({ $path: new URL(req.url).pathname, $ts: Date.now() });
    const count = db.query("SELECT COUNT(*) as n FROM hits").get() as { n: number };
    return Response.json({ hits: count.n });
  },
});
